    55	/*
    56	 * ATOM command and data table indices.
    57	 *
    58	 * The master command/data table layout differs between atombios.h (v1,
    59	 * pre-Vega) and atomfirmware.h (v2, Vega+). The ATOM bytecode interpreter
    60	 * is format-agnostic, but command table indices differ because the v2
    61	 * master table has a different field order.
    62	 *
    63	 * We detect the format at runtime from the master table header revision
    64	 * and store the resolved indices in an atombios_cmd_table_idx struct.
    65	 */
    66	
    67	/* v1 index: offsetof into ATOM_MASTER_LIST_OF_COMMAND_TABLES */
    68	#define CMD_IDX_V1(field) \
    69		(offsetof(ATOM_MASTER_LIST_OF_COMMAND_TABLES, field) / sizeof(USHORT))
    70	
    71	/* v2 index: offsetof into atom_master_list_of_command_functions_v2_1 */
    72	#define CMD_IDX_V2(field) \
    73		(offsetof(struct atom_master_list_of_command_functions_v2_1, field) / sizeof(uint16_t))
    74	
    75	/* v1 data index: offsetof into ATOM_MASTER_LIST_OF_DATA_TABLES */
    76	#define DATA_IDX_V1(field) \
    77		(offsetof(ATOM_MASTER_LIST_OF_DATA_TABLES, field) / sizeof(USHORT))
    78	
    79	/* v2 data index: offsetof into atom_master_list_of_data_tables_v2_1 */
    80	#define DATA_IDX_V2(field) \
    81		(offsetof(struct atom_master_list_of_data_tables_v2_1, field) / sizeof(uint16_t))
