4555	static int atomfirmware_init_display_pipes(struct atom_context *ctx, uint8_t pipe_count)
4556	{
4557		uint32_t params[5] = { 0 };
4558		uint8_t pipe;
4559	
4560		if (!pipe_count || pipe_count > 6)
4561			return -1;
4562	
4563		/* Linux dcn10_bios_golden_init(): global init, then disable every pipe. */
4564		params[0] = ATOM_INIT << 8;
4565		if (atombios_exec(ctx, cmd_idx.enable_disp_power_gating,
4566				 params, sizeof(params)))
4567			return -1;
4568		for (pipe = 0; pipe < pipe_count; pipe++) {
4569			params[0] = pipe | (ATOM_DISABLE << 8);
4570			if (atombios_exec(ctx, cmd_idx.enable_disp_power_gating,
4571					 params, sizeof(params)))
4572				return -1;
4573		}
4574		return 0;
4575	}
