4577	static struct atombios_display_path
4578	atomfirmware_edp_path(const struct atom_v2_display_path *v2_path)
4579	{
4580		struct atombios_display_path path = {
4581			.connector_type = 2,
4582			.encoder_obj_id = atombios_object_id(v2_path->encoder_objid),
4583			.i2c_line = v2_path->i2c_id,
4584			.i2c_valid = v2_path->i2c_valid,
4585			.hpd_id = v2_path->hpd_valid ? v2_path->hpd_pin : v2_path->phy_id,
4586			.dig_encoder = v2_path->dig_encoder,
4587			.phy_id = v2_path->phy_id,
4588			.encoder_mode = ATOM_ENCODER_MODE_DP,
4589			.pll_id = ATOM_COMBOPHY_PLL0 + v2_path->phy_id,
4590			.tx_refclk = ATOM_COMBOPHY_PLL0 + v2_path->phy_id,
4591			.connector_obj_id = CONNECTOR_OBJECT_ID_eDP,
4592			.device_tag = v2_path->device_tag,
4593		};
4594	
4595		return path;
4596	}
