4598	static int atomfirmware_prepare_edp_link(struct atom_context *ctx,
4599						 const struct atom_v2_display_path *v2_path,
4600						 const struct edid_mode *mode,
4601						 struct atombios_display_path *path)
4602	{
4603		uint16_t pixel_clock_10khz = mode->pixel_clock / 10;
4604	
4605		*path = atomfirmware_edp_path(v2_path);
4606		/* DCN owns OTG timing and blanking; Atom owns PLL, DIG and PHY services. */
4607		return atombios_dp_prepare_link(ctx, path, mode->pixel_clock) ||
4608			atombios_transmitter_control(ctx, path, pixel_clock_10khz,
4609						    ATOM_TRANSMITTER_ACTION_INIT, 0, 0) ||
4610			atombios_dig_encoder_setup(ctx, path, pixel_clock_10khz,
4611						   ATOM_ENCODER_CMD_STREAM_SETUP,
4612						   PANEL_8BIT_PER_COLOR) ||
4613			atombios_dig_encoder_setup(ctx, path, pixel_clock_10khz,
4614						   ATOM_ENCODER_CMD_SETUP_PANEL_MODE,
4615						   PANEL_8BIT_PER_COLOR) ||
4616			atombios_select_crtc_source(ctx, path, ATOM_CRTC1) ||
4617			atombios_set_pixel_clock(ctx, path, pixel_clock_10khz, ATOM_CRTC1);
4618	}
