4620	static int atomfirmware_train_edp_link(struct atom_context *ctx,
4621					       struct atombios_display_path *path,
4622					       const struct edid_mode *mode)
4623	{
4624		uint16_t pixel_clock_10khz = mode->pixel_clock / 10;
4625	
4626		return atombios_transmitter_control(ctx, path, pixel_clock_10khz,
4627						    ATOM_TRANSMITTER_ACTION_ENABLE, 0, 0) ||
4628			atombios_dp_link_train(ctx, path, pixel_clock_10khz,
4629					       path->i2c_line, path->hpd_id);
4630	}
