4633						     struct atombios_display_path *path,
4634						     const struct edid_mode *mode)
4635	{
4636		return atombios_transmitter_control(ctx, path, mode->pixel_clock / 10,
4637						    ATOM_TRANSMITTER_ACTION_LCD_BLON, 0, 0);
4638	}
