4641	
4642	void amd_atombios_init(struct device *dev)
4643	{
4644		struct card_info *card;
4645		struct atom_context *ctx;
4646		struct atom_context v2_ctx;
4647		struct atom_v2_rom_info v2_rom;
4648		struct atom_v2_display_info v2_display;
4649		struct atom_v2_firmware_info v2_fw;
4650		struct atom_v2_dce_info v2_dce;
4651		const void *v2_table;
4652		size_t v2_table_size;
4653		void *vbios;
4654		size_t vbios_size;
4655		resource_t mmio_bar, fb_bar;
4656		struct resource *fb_res;
4657		size_t fb_size = 0;
4658		void *mmio_base;
4659		uint32_t *scratch;
4660		int crtc_id = ATOM_CRTC1;
4661		struct edid_mode mode;
4662		struct atombios_display_path paths[8];
4663		int num_paths;
4664		int active_path = -1;
4665		uint8_t edid_raw[EDID_BLOCK_SIZE];
4666		struct edid edid;
4667		uint16_t pixel_clock_10khz;
4668		bool asic_init_ok = false;
4669		bool expected_v2 = atomfirmware_display_ip(dev->device) !=
4670			ATOMFIRMWARE_DISPLAY_IP_UNKNOWN;
4671		struct atombios_gpu_profile gpu = atombios_get_gpu_profile(dev->device);
4672		int i;
4673	
4674		printk(BIOS_INFO, "ATOMBIOS: initializing AMD GPU %04x:%04x\n",
4675		       dev->vendor, dev->device);
4676	
4677		if (!CONFIG(MAINBOARD_DO_NATIVE_VGA_INIT)) {
4678			printk(BIOS_INFO, "ATOMBIOS: native graphics initialization disabled\n");
4679			return;
4680		}
4681	
4682		if (!gpu.supported || !gpu.has_display) {
4683			printk(BIOS_WARNING,
4684			       "ATOMBIOS: GPU %04x has no supported display engine\n",
4685			       dev->device);
4686			return;
4687		}
4688	
4689		/* Map MMIO BAR */
4690		mmio_bar = atombios_get_bar(dev, AMD_GPU_MMIO_BAR);
4691		if (!mmio_bar)
4692			mmio_bar = atombios_get_bar(dev, PCI_BASE_ADDRESS_2);
4693		if (!mmio_bar && !expected_v2) {
4694			printk(BIOS_ERR, "ATOMBIOS: could not find MMIO BAR\n");
4695			return;
4696		}
4697		mmio_base = (void *)(uintptr_t)mmio_bar;
4698		if (mmio_bar)
4699			printk(BIOS_INFO, "ATOMBIOS: MMIO base at %p\n", mmio_base);
4700		else
4701			printk(BIOS_WARNING, "ATOMBIOS: MMIO BAR unavailable for diagnostics\n");
4702	
4703		/* Get framebuffer BAR.  This is often a 64-bit BAR above 4 GiB. */
4704		fb_bar = atombios_get_bar(dev, AMD_GPU_FB_BAR);
4705		if (!fb_bar && !expected_v2) {
4706			printk(BIOS_ERR, "ATOMBIOS: could not find FB BAR\n");
4707			return;
4708		}
4709		if (fb_bar) {
4710			fb_res = probe_resource(dev, AMD_GPU_FB_BAR);
4711			if (fb_res)
4712				fb_size = fb_res->size;
4713			printk(BIOS_INFO, "ATOMBIOS: framebuffer aperture at 0x%llx\n",
4714			       (unsigned long long)fb_bar);
4715		} else
4716			printk(BIOS_WARNING, "ATOMBIOS: framebuffer BAR unavailable for diagnostics\n");
4717	
4718		/* Load VBIOS */
4719		vbios = load_vbios(dev, &vbios_size);
4720		if (!vbios)
4721			return;
4722	
4723		/* Set up card_info callbacks */
4724		card = calloc(1, sizeof(struct card_info));
4725		if (!card) {
4726			printk(BIOS_ERR, "ATOMBIOS: failed to allocate card_info\n");
4727			return;
4728		}
4729		card->mmio_base = mmio_base;
4730		card->reg_write = cail_reg_write;
4731		card->reg_read = cail_reg_read;
4732		card->mc_write = cail_mc_write;
4733		card->mc_read = cail_mc_read;
4734		card->pll_write = cail_pll_write;
4735		card->pll_read = cail_pll_read;
4736	
4737		if (expected_v2) {
4738			if (atom_v2_parse_rom_header(vbios, vbios_size, &v2_rom)) {
4739				printk(BIOS_WARNING,
4740				       "ATOMBIOS: malformed or unsupported AtomFirmware v2 ROM header\n");
4741				return;
4742			}
4743	
4744			memset(&v2_ctx, 0, sizeof(v2_ctx));
4745			v2_ctx.card = card;
4746			v2_ctx.bios = vbios;
4747			v2_ctx.cmd_table = v2_rom.command_table_offset;
4748			v2_ctx.data_table = v2_rom.data_table_offset;
4749			atombios_init_cmd_indices_v2(&cmd_idx);
4750			atomfirmware_diagnostics(&v2_ctx, vbios_size, dev->device);
4751	
4752			if (!mmio_base) {
4753				printk(BIOS_ERR, "ATOMBIOS: MMIO BAR required for v2 ASIC_Init\n");
4754				return;
4755			}
4756			if (atom_v2_get_table(vbios, vbios_size, v2_rom.data_table_offset,
4757					      DATA_IDX_V2(indirectioaccess), &v2_table,
4758					      &v2_table_size) || v2_table_size < 4) {
4759				printk(BIOS_ERR, "ATOMBIOS: v2 IndirectIOAccess table unavailable\n");
4760				return;
4761			}
4762			atom_initialize_iio(&v2_ctx,
4763					    (const uint8_t *)v2_table - (const uint8_t *)vbios + 4);
4764			if (!v2_ctx.iio) {
4765				printk(BIOS_ERR, "ATOMBIOS: failed to initialize v2 indirect I/O\n");
4766				return;
4767			}
4768	
4769			scratch = calloc(ATOM_SCRATCH_SIZE_DWORDS, sizeof(uint32_t));
4770			if (!scratch) {
4771				printk(BIOS_ERR, "ATOMBIOS: failed to allocate scratch memory\n");
4772				return;
4773			}
4774			v2_ctx.scratch = scratch;
4775			v2_ctx.scratch_size_bytes = ATOM_SCRATCH_SIZE_DWORDS * sizeof(uint32_t);
4776	
4777			if (atom_v2_get_table(vbios, vbios_size, v2_rom.data_table_offset,
4778					      DATA_IDX_V2(firmwareinfo), &v2_table,
4779					      &v2_table_size) ||
4780			    atom_v2_parse_firmware_info(v2_table, v2_table_size, &v2_fw)) {
4781				printk(BIOS_ERR, "ATOMBIOS: v2 FirmwareInfo unavailable for ASIC_Init\n");
4782				return;
4783			}
4784			if (atom_v2_get_table(vbios, vbios_size, v2_rom.data_table_offset,
4785					      DATA_IDX_V2(dce_info), &v2_table, &v2_table_size) ||
4786			    atom_v2_parse_dce_info(v2_table, v2_table_size, &v2_dce)) {
4787				printk(BIOS_ERR, "ATOMBIOS: v2 DCE_Info unavailable for DCN setup\n");
4788				return;
4789			}
4790			if (atomfirmware_asic_init(&v2_ctx, &v2_fw)) {
4791				printk(BIOS_ERR, "ATOMBIOS: AtomFirmware v2 ASIC_Init failed\n");
4792				return;
4793			}
4794			printk(BIOS_INFO, "ATOMBIOS: AtomFirmware v2 ASIC_Init complete\n");
4795			if (dev->device == 0x15d8) {
4796				dcn10_disable_vga(mmio_base);
4797				if (atomfirmware_init_display_pipes(&v2_ctx, v2_dce.max_pipes) ||
4798				    dcn10_cold_init(mmio_base, v2_dce.max_pipes)) {
4799					printk(BIOS_ERR, "ATOMBIOS: DCN1 display-pipe init failed\n");
4800					return;
4801				}
4802				printk(BIOS_INFO, "ATOMBIOS: DCN1 display pipe initialized\n");
4803				if (atomfirmware_power_edp(&v2_ctx)) {
4804					printk(BIOS_ERR, "ATOMBIOS: DCN1 eDP panel power-on failed\n");
4805					return;
4806				}
4807				printk(BIOS_INFO, "ATOMBIOS: DCN1 eDP panel powered on\n");
4808			}
4809	
4810			if (atom_v2_get_table(vbios, vbios_size, v2_rom.data_table_offset,
4811					      DATA_IDX_V2(displayobjectinfo), &v2_table,
4812					      &v2_table_size) ||
4813			    atom_v2_parse_display_object_info(v2_table, v2_table_size,
4814						      &v2_display)) {
4815				printk(BIOS_ERR, "ATOMBIOS: v2 display paths unavailable\n");
4816				return;
4817			}
4818	
4819			for (i = 0; i < v2_display.path_count; i++) {
4820				const struct atom_v2_display_path *path = &v2_display.paths[i];
4821				uint8_t dpcd[3];
4822				uint8_t hpd_id;
4823	
4824				if (!path->i2c_valid || path->dig_encoder == 0xff)
4825					continue;
4826				hpd_id = path->hpd_valid ? path->hpd_pin : path->phy_id;
4827				if (dp_aux_native_read(&v2_ctx, path->i2c_id, hpd_id,
4828						       DP_DPCD_REV, dpcd, sizeof(dpcd))) {
4829					printk(BIOS_INFO,
4830					       "ATOMBIOS: v2 path %d no DPCD response on AUX 0x%02x HPD%u\n",
4831					       i, path->i2c_id, hpd_id + 1);
4832					continue;
4833				}
4834	
4835				printk(BIOS_INFO,
4836				       "ATOMBIOS: v2 path %d AUX detected DPCD %x.%x rate=0x%02x lanes=%u\n",
4837				       i, dpcd[0] >> 4, dpcd[0] & 0xf, dpcd[1],
4838				       dpcd[2] & 0x1f);
4839				if (!atombios_dp_read_edid(&v2_ctx, path->i2c_id, hpd_id,
4840							     edid_raw) &&
4841				    decode_edid(edid_raw, EDID_BLOCK_SIZE, &edid) == EDID_CONFORMANT) {
4842					printk(BIOS_INFO,
4843					       "ATOMBIOS: v2 display path %d: %s %dx%d @ %u kHz\n",
4844					       i, edid.ascii_string, edid.mode.ha, edid.mode.va,
4845					       edid.mode.pixel_clock);
4846					if (dev->device == 0x15d8) {
4847						struct dcn10_timing timing = {
4848							.h_active = edid.mode.ha,
4849							.h_blank = edid.mode.hbl,
4850							.h_front_porch = edid.mode.hso,
4851							.h_sync_width = edid.mode.hspw,
4852							.v_active = edid.mode.va,
4853							.v_blank = edid.mode.vbl,
4854							.v_front_porch = edid.mode.vso,
4855							.v_sync_width = edid.mode.vspw,
4856							.pixel_clock_khz = edid.mode.pixel_clock,
4857							.ref_clock_khz = v2_dce.dce_refclk_10khz * 10,
4858							.disp_clock_khz = v2_dce.boot_dispclk_10khz * 10,
4859							.hsync_positive = edid.mode.phsync,
4860							.vsync_positive = edid.mode.pvsync,
4861						};
4862						struct atombios_display_path edp_path;
4863						uint32_t pitch;
4864	
4865						if (atomfirmware_prepare_edp_link(&v2_ctx, path, &edid.mode,
4866									       &edp_path) ||
4867						    dcn10_program_stream(mmio_base, &timing) ||
4868						    atomfirmware_train_edp_link(&v2_ctx, &edp_path,
4869									     &edid.mode)) {
4870							printk(BIOS_ERR,
4871							       "ATOMBIOS: DCN1 eDP stream/link setup failed\n");
4872							return;
4873						}
4874						if (dcn10_program_scanout(mmio_base, v2_fw.mc_base,
4875								   (void *)(uintptr_t)fb_bar, fb_size,
4876								   &timing, &pitch)) {
4877							printk(BIOS_ERR,
4878							       "ATOMBIOS: DCN1 framebuffer scanout failed\n");
4879							return;
4880						}
4881						if (atomfirmware_enable_edp_backlight(&v2_ctx, &edp_path,
4882									       &edid.mode)) {
4883							printk(BIOS_ERR,
4884							       "ATOMBIOS: DCN1 backlight enable failed\n");
4885							return;
4886						}
4887						fb_add_framebuffer_info(fb_bar, edid.mode.ha,
4888								edid.mode.va, pitch, DEFAULT_BPP);
4889						printk(BIOS_INFO,
4890						       "ATOMBIOS: DCN1 framebuffer registered\n");
4891					}
4892					break;
4893				}
4894			}
4895			return;

