4553	}
4554	
4555	static int atomfirmware_init_display_pipes(struct atom_context *ctx, uint8_t pipe_count)
4556	{
4557		uint32_t params[5] = { 0 };
4558		uint8_t pipe;
4559	
4560		if (!pipe_count || pipe_count > 6)
4561			return -1;
4562	
4563		/* Linux dcn10_bios_golden_init(): global init, then disable every pipe. */
4564		params[0] = ATOM_INIT << 8;
4565		if (atombios_exec(ctx, cmd_idx.enable_disp_power_gating,
4566				 params, sizeof(params)))
4567			return -1;
4568		for (pipe = 0; pipe < pipe_count; pipe++) {
4569			params[0] = pipe | (ATOM_DISABLE << 8);
4570			if (atombios_exec(ctx, cmd_idx.enable_disp_power_gating,
4571					 params, sizeof(params)))
4572				return -1;
4573		}
4574		return 0;
4575	}
4576	
4577	static struct atombios_display_path
4578	atomfirmware_edp_path(const struct atom_v2_display_path *v2_path)
4579	{
4580		struct atombios_display_path path = {
4581			.connector_type = 2,
4582			.encoder_obj_id = atombios_object_id(v2_path->encoder_objid),
4583			.i2c_line = v2_path->i2c_id,
4584			.i2c_valid = v2_path->i2c_valid,
4585			.hpd_id = v2_path->hpd_valid ? v2_path->hpd_pin : v2_path->phy_id,
4586			.dig_encoder = v2_path->dig_encoder,
4587			.phy_id = v2_path->phy_id,
4588			.encoder_mode = ATOM_ENCODER_MODE_DP,
4589			.pll_id = ATOM_COMBOPHY_PLL0 + v2_path->phy_id,
4590			.tx_refclk = ATOM_COMBOPHY_PLL0 + v2_path->phy_id,
4591			.connector_obj_id = CONNECTOR_OBJECT_ID_eDP,
4592			.device_tag = v2_path->device_tag,
4593		};
4594	
4595		return path;
4596	}
4597	
4598	static int atomfirmware_prepare_edp_link(struct atom_context *ctx,
4599						 const struct atom_v2_display_path *v2_path,
4600						 const struct edid_mode *mode,
4601						 struct atombios_display_path *path)
4602	{
4603		uint16_t pixel_clock_10khz = mode->pixel_clock / 10;
4604	
4605		*path = atomfirmware_edp_path(v2_path);
4606		/* DCN owns OTG timing and blanking; Atom owns PLL, DIG and PHY services. */
4607		return atombios_dp_prepare_link(ctx, path, mode->pixel_clock) ||
4608			atombios_transmitter_control(ctx, path, pixel_clock_10khz,
4609						    ATOM_TRANSMITTER_ACTION_INIT, 0, 0) ||
4610			atombios_dig_encoder_setup(ctx, path, pixel_clock_10khz,
4611						   ATOM_ENCODER_CMD_STREAM_SETUP,
4612						   PANEL_8BIT_PER_COLOR) ||
4613			atombios_dig_encoder_setup(ctx, path, pixel_clock_10khz,
4614						   ATOM_ENCODER_CMD_SETUP_PANEL_MODE,
4615						   PANEL_8BIT_PER_COLOR) ||
4616			atombios_select_crtc_source(ctx, path, ATOM_CRTC1) ||
4617			atombios_set_pixel_clock(ctx, path, pixel_clock_10khz, ATOM_CRTC1);
4618	}
4619	
4620	static int atomfirmware_train_edp_link(struct atom_context *ctx,
4621					       struct atombios_display_path *path,
4622					       const struct edid_mode *mode)
4623	{
4624		uint16_t pixel_clock_10khz = mode->pixel_clock / 10;
4625	
4626		return atombios_transmitter_control(ctx, path, pixel_clock_10khz,
4627						    ATOM_TRANSMITTER_ACTION_ENABLE, 0, 0) ||
4628			atombios_dp_link_train(ctx, path, pixel_clock_10khz,
4629					       path->i2c_line, path->hpd_id);
4630	}
4631	
4632	static int atomfirmware_enable_edp_backlight(struct atom_context *ctx,
4633						     struct atombios_display_path *path,
4634						     const struct edid_mode *mode)
4635	{
4636		return atombios_transmitter_control(ctx, path, mode->pixel_clock / 10,
4637						    ATOM_TRANSMITTER_ACTION_LCD_BLON, 0, 0);
4638	}
