  1055		/* TODO setup link_enc */
  1056		/* TODO set stream attributes */
  1057		/* TODO program audio */
  1058		/* TODO enable stream if timing changed */
  1059		/* TODO unblank stream if DP */
  1060	
  1061		return DC_OK;
