   652		REG_WRITE(D1VGA_CONTROL, 0);
   653		REG_WRITE(D2VGA_CONTROL, 0);
   654		REG_WRITE(D3VGA_CONTROL, 0);
   655		REG_WRITE(D4VGA_CONTROL, 0);
