  1337	void dcn10_disable_plane(struct dc *dc, struct dc_state *state, struct pipe_ctx *pipe_ctx)
  1338	{
  1339		struct dce_hwseq *hws = dc->hwseq;
  1340		DC_LOGGER_INIT(dc->ctx->logger);
