2951			stream_res->tg->funcs->set_blank_color(
2952					stream_res->tg,
2953					&black_color);
2954	
2955		if (!blank) {
2956			if (stream_res->tg->funcs->set_blank)
2957				stream_res->tg->funcs->set_blank(stream_res->tg, blank);
